package be.schaubroeck.lpb.rkm.rekenmotor.bruto;

import be.schaubroeck.lpb.rkm.rekenmotor.RekenTijd;
import be.schaubroeck.lpb.rkm.rekenmotor.SleutelGegevens;
import be.schaubroeck.lpb.rkm.rekenmotor.keys.UitzPerUurModus;
import be.schaubroeck.lpb.rkm.rekenmotor.util.Breuk;
import be.schaubroeck.lpb.rkm.rekenmotor.util.RegulManager;
import be.schaubroeck.lpb.rkm.rekenmotor.util.RekenTools;
import be.schaubroeck.lpb.tools.Opper;
import be.schaubroeck.lpb.tools.enumtypes.AkeTijdperk;
import be.schaubroeck.lpb.tools.enumtypes.DmfapplWnkengetal;
import be.schaubroeck.lpb.tools.enumtypes.PvhVorming;
import be.schaubroeck.lpb.tools.enumtypes.Regulkode;
import be.schaubroeck.lpb.tools.enumtypes.Rekenwijze;
import be.schaubroeck.lpb.tools.enumtypes.WerkgeversCategorie;
import be.schaubroeck.lpb.tools.model.AfwezigheidBO;
import com.google.common.collect.ImmutableSet;

import java.math.BigDecimal;
import java.util.Set;

public class RkmPrestatieVerhouding {

    private RkmPrestatieVerhouding() {
    }

    private static final Set<Integer> AFWEZIGHEIDSCODES_MANUELE_PVH_RSZPPO = ImmutableSet.of(150, 151, 161, 171, 180);
    private static final Set<Integer> AFWEZIGHEIDSCODES_MANUELE_PVH_DMFAPPL = ImmutableSet.of(150, 151, 152, 153, 161, 180);
    private static final Set<UitzPerUurModus> GEEN_MANUELE_PVH =
            ImmutableSet.of(UitzPerUurModus.UIITZONDERLIJK_PER_UUR_NEW, UitzPerUurModus.UITZ_PER_UUR_LANGDURIG_AFWEZIGHEID_NEW);
    private static final Set<UitzPerUurModus> GEBRUIKT_AFWEZIGHEDEN_INVOER_MODULE =
            ImmutableSet.of(UitzPerUurModus.UITZ_PER_UUR_LANGDURIG_AFWEZIGHEID, UitzPerUurModus.UIITZONDERLIJK_PER_UUR_NEW,
                    UitzPerUurModus.UITZ_PER_UUR_LANGDURIG_AFWEZIGHEID_NEW);

    public static BigDecimal bepaal(SleutelGegevens gegevens, UitzPerUurModus uitzPerUurModus, RegulManager regulManager, boolean begroting) {
        return bepaal(gegevens, false, uitzPerUurModus, regulManager, begroting);
    }

    public static Breuk bepaalBreuk(SleutelGegevens gegevens, RegulManager regulManager) {
        return bepaalBreuk(gegevens, false, UitzPerUurModus.GEEN, regulManager, false);
    }

    public static BigDecimal bepaal(SleutelGegevens gegevens, RegulManager regulManager) {
        return bepaal(gegevens, false, UitzPerUurModus.GEEN, regulManager, false);
    }

    public static BigDecimal bepaalTheoretisch(SleutelGegevens gegevens, RegulManager regulManager, boolean begroting) {
        return bepaal(gegevens, true, UitzPerUurModus.GEEN, regulManager, begroting);
    }

    public static boolean isAfwezigheidsCodeMetManuelePrestatieVerhouding(Opper opper, RekenTijd rekenTijd) {
        AkeTijdperk tijdperk = RekenTools.getTijdperk(rekenTijd);
        int afwezigheidsCode = opper.getRszppo().getAfwezigheidsCode();
        boolean resultaat;
        if (tijdperk == AkeTijdperk.RSZPPO) {
            resultaat = AFWEZIGHEIDSCODES_MANUELE_PVH_RSZPPO.contains(afwezigheidsCode);
        } else {
            resultaat = AFWEZIGHEIDSCODES_MANUELE_PVH_DMFAPPL.contains(afwezigheidsCode);
        }
        return resultaat;
    }

    public static BigDecimal bepaal(
            SleutelGegevens gegevens, boolean theoretisch, UitzPerUurModus uitzPerUurModus, RegulManager regulManager, boolean begroting) {
        Breuk breuk = bepaalBreuk(gegevens, theoretisch, uitzPerUurModus, regulManager, begroting);
        return breuk.getBigDecimal();
    }

    public static Breuk bepaalBreuk(
            SleutelGegevens gegevens, boolean theoretisch, UitzPerUurModus uitzPerUurModus, RegulManager regulManager, boolean begroting) {
        if (gegevens.getWerknemersKengetal() != DmfapplWnkengetal.NVT && gegevens.getWerkgeversCategorie() != WerkgeversCategorie.NVT && (
                gegevens.getAanstelling().signum() == 0 && gegevens.getMaatman().signum() == 0)) {
            regulManager.doRegulException(gegevens.getOpdracht(), Regulkode.PVH_ZERO_ZERO);
        }
        BigDecimal aanstelling = BigDecimal.ONE;
        BigDecimal maatman = BigDecimal.ONE;
        if (heeftPrestatieVerhouding(gegevens, theoretisch)) {
            if (gegevens.getPrestatieVerhoudingVorming() == PvhVorming.MANUEEL && !GEEN_MANUELE_PVH.contains(uitzPerUurModus)) {
                aanstelling = gegevens.getTellerPrestatieVerhouding();
                maatman = gegevens.getNoemerPrestatieVerhouding();
            } else if (gegevens.getAanstelling().compareTo(RekenTools.ONREGELMATIG_PER_PRESTATIE) != 0 && gegevens.getMaatman().signum() != 0) {

                aanstelling = bepaalAanstellingAutomatisch(gegevens, uitzPerUurModus, begroting);
                maatman = gegevens.getMaatman();
            }
        }
        return vormBreukMetNoemerCheckNietNul(aanstelling, maatman, gegevens, regulManager);
    }

    private static BigDecimal bepaalAanstellingAutomatisch(SleutelGegevens gegevens, UitzPerUurModus uitzPerUurModus, boolean begroting) {
        BigDecimal aanstelling = gegevens.getAanstelling();
        if (GEBRUIKT_AFWEZIGHEDEN_INVOER_MODULE.contains(uitzPerUurModus) && !gegevens.getAfwezighedenInvoerModule().isEmpty()) {
            BigDecimal afwezigheidsUren = getAfwezighedenUrenUitzPerUur(gegevens);
            return aanstelling.subtract(afwezigheidsUren);
        } else if (gegevens.getAfwezigheidsCode() != 0 && uitzPerUurModus != UitzPerUurModus.UIITZONDERLIJK_PER_UUR) {
            BigDecimal afwezigheidsUren = getAfwezighedenUren(gegevens, begroting);
            return aanstelling.subtract(afwezigheidsUren);
        } else {
            return aanstelling;
        }
    }

    private static BigDecimal getAfwezighedenUrenUitzPerUur(SleutelGegevens gegevens) {
        return gegevens.getAfwezighedenInvoerModule().stream()
                .filter(x -> !x.isCodeDispo())
                .filter(x -> !x.isBetaaldeAfwezigheid100())
                .map(AfwezigheidBO::getHours).reduce(BigDecimal.ZERO, BigDecimal::add);
    }

    private static BigDecimal getAfwezighedenUren(SleutelGegevens gegevens, boolean invoerModule) {
        if (invoerModule) {
            return gegevens.getAfwezighedenInvoerModule().stream().map(AfwezigheidBO::getHours).reduce(BigDecimal.ZERO, BigDecimal::add);
        } else {
            return gegevens.getAfwezigheidsUren();
        }
    }

    private static boolean heeftPrestatieVerhouding(SleutelGegevens gegevens, boolean theoretisch) {
        return gegevens.getRekenWijze() == Rekenwijze.MAAND || (gegevens.getRekenWijze() == Rekenwijze.UUR && theoretisch);
    }

    private static Breuk vormBreukMetNoemerCheckNietNul(BigDecimal aanstelling, BigDecimal maatman, SleutelGegevens gegevens, RegulManager regulManager) {
        if (maatman.signum() == 0) {
            doRegulNoemerIsNull(gegevens, regulManager);
            return new Breuk(BigDecimal.ONE, BigDecimal.ONE);
        } else {
            return new Breuk(aanstelling, maatman);
        }
    }

    private static void doRegulNoemerIsNull(SleutelGegevens gegevens, RegulManager regulManager) {
        Regulkode noemerIsNul = null;
        if (gegevens.getPrestatieVerhoudingVorming() == PvhVorming.MANUEEL) {
            noemerIsNul = Regulkode.PVH_NOEMER_NUL;
        } else if (gegevens.getAanstelling().compareTo(RekenTools.ONREGELMATIG_PER_PRESTATIE) != 0) {
            noemerIsNul = Regulkode.MAATMAN_NUL;
        }
        regulManager.doRegulException(gegevens.getOpdracht(), noemerIsNul);
    }
}
